using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Alice Chen", Title = "Professor of Computer Science", Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 peer-reviewed papers and holds two patents in natural language processing. She received her Ph.D. from MIT and has been teaching for 15 years.", Email = "achen@university.edu" },
            new() { Id = 2, Name = "Dr. Robert Martinez", Title = "Associate Professor of Mathematics", Bio = "Dr. Martinez focuses on applied mathematics and statistics. His research bridges theoretical math with practical data science applications. He is a recipient of the National Science Foundation CAREER Award.", Email = "rmartinez@university.edu" },
            new() { Id = 3, Name = "Dr. Sarah Johnson", Title = "Professor of English", Bio = "Dr. Johnson is an award-winning author and literary critic specializing in contemporary American fiction. She has served as editor of the Literary Review and mentored dozens of published writers.", Email = "sjohnson@university.edu" },
            new() { Id = 4, Name = "Dr. James Park", Title = "Assistant Professor of Physics", Bio = "Dr. Park researches quantum computing and condensed matter physics. He completed postdoctoral work at CERN and brings cutting-edge research into his undergraduate courses.", Email = "jpark@university.edu" },
            new() { Id = 5, Name = "Dr. Maria Lopez", Title = "Professor of History", Bio = "Dr. Lopez is a historian of Latin American studies with a focus on colonial and post-colonial periods. She has authored three books and regularly contributes to historical documentaries.", Email = "mlopez@university.edu" },
            new() { Id = 6, Name = "Dr. David Kim", Title = "Associate Professor of Chemistry", Bio = "Dr. Kim specializes in organic chemistry and pharmaceutical research. He previously worked at a major pharmaceutical company and brings industry experience to his teaching.", Email = "dkim@university.edu" },
            new() { Id = 7, Name = "Dr. Emily Wright", Title = "Professor of Psychology", Bio = "Dr. Wright is a clinical psychologist and researcher in cognitive behavioral therapy. She runs the university's Behavioral Research Lab and has trained over 100 graduate students.", Email = "ewright@university.edu" },
            new() { Id = 8, Name = "Dr. Michael Brown", Title = "Associate Professor of Economics", Bio = "Dr. Brown researches international trade and macroeconomic policy. He has consulted for the World Bank and several government agencies on economic development.", Email = "mbrown@university.edu" },
        };

        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Explore computing theory, software engineering, artificial intelligence, and data systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study pure and applied mathematics including calculus, algebra, statistics, and modeling." },
            new() { Id = 3, Name = "English", Code = "ENG", Description = "Develop skills in writing, literary analysis, and critical thinking across diverse texts." },
            new() { Id = 4, Name = "Physics", Code = "PHYS", Description = "Investigate the fundamental laws of nature from classical mechanics to quantum theory." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Examine the past to understand societies, cultures, and global events that shaped the modern world." },
            new() { Id = 6, Name = "Chemistry", Code = "CHEM", Description = "Study matter at the molecular level including reactions, synthesis, and analytical techniques." },
            new() { Id = 7, Name = "Psychology", Code = "PSY", Description = "Understand human behavior and mental processes through scientific research and clinical practice." },
            new() { Id = 8, Name = "Economics", Code = "ECON", Description = "Analyze markets, policy, trade, and decision-making in local and global economies." },
        };

        _courses = new List<Course>
        {
            // Computer Science
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, data structures, and basic algorithms. No prior programming experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Location = "Science Hall 201", DepartmentId = 1, InstructorId = 1, IsFeatured = true },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study fundamental data structures (arrays, linked lists, trees, graphs, hash tables) and algorithm design techniques (sorting, searching, dynamic programming). Prerequisites: CS 101.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", Location = "Science Hall 305", DepartmentId = 1, InstructorId = 1 },
            new() { Id = 3, Code = "CS 330", Title = "Artificial Intelligence", Description = "Introduction to AI concepts including search algorithms, knowledge representation, machine learning fundamentals, and neural networks. Prerequisites: CS 201, MATH 201.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", Location = "Tech Center 110", DepartmentId = 1, InstructorId = 1, IsFeatured = true },

            // Mathematics
            new() { Id = 4, Code = "MATH 101", Title = "Calculus I", Description = "First course in single-variable calculus covering limits, derivatives, and integrals with applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Location = "Math Building 102", DepartmentId = 2, InstructorId = 2 },
            new() { Id = 5, Code = "MATH 201", Title = "Linear Algebra", Description = "Study of vector spaces, matrices, linear transformations, eigenvalues, and applications to data science and engineering.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", Location = "Math Building 204", DepartmentId = 2, InstructorId = 2, IsFeatured = true },
            new() { Id = 6, Code = "MATH 310", Title = "Probability & Statistics", Description = "Introduction to probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", Location = "Math Building 102", DepartmentId = 2, InstructorId = 2 },

            // English
            new() { Id = 7, Code = "ENG 101", Title = "College Composition", Description = "Develop clear, effective writing skills through essays, research papers, and peer review. Emphasis on argumentation and evidence-based writing.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Location = "Humanities 105", DepartmentId = 3, InstructorId = 3 },
            new() { Id = 8, Code = "ENG 220", Title = "American Literature", Description = "Survey of American literature from the colonial period to the present, examining major authors, themes, and literary movements.", Credits = 3, Schedule = "Tue/Thu 10:30–11:50 AM", Location = "Humanities 210", DepartmentId = 3, InstructorId = 3, IsFeatured = true },
            new() { Id = 9, Code = "ENG 315", Title = "Creative Writing Workshop", Description = "Workshop-based course in fiction and poetry writing. Students produce original work and participate in peer critique sessions.", Credits = 3, Schedule = "Wed 3:00–5:50 PM", Location = "Humanities 312", DepartmentId = 3, InstructorId = 3 },

            // Physics
            new() { Id = 10, Code = "PHYS 101", Title = "General Physics I", Description = "Introduction to classical mechanics, thermodynamics, and waves. Includes weekly lab sessions. Co-requisite: MATH 101.", Credits = 4, Schedule = "Tue/Thu 9:00–10:20 AM", Location = "Physics Lab 101", DepartmentId = 4, InstructorId = 4 },
            new() { Id = 11, Code = "PHYS 301", Title = "Quantum Mechanics", Description = "Introduction to quantum theory including wave-particle duality, the Schrödinger equation, and applications to atomic and molecular systems.", Credits = 3, Schedule = "Mon/Wed 10:00–11:20 AM", Location = "Physics Lab 203", DepartmentId = 4, InstructorId = 4, IsFeatured = true },

            // History
            new() { Id = 12, Code = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations, empires, and cultural developments from prehistory through the late medieval period.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", Location = "Liberal Arts 110", DepartmentId = 5, InstructorId = 5 },
            new() { Id = 13, Code = "HIST 250", Title = "Latin American History", Description = "Explore the history of Latin America from pre-Columbian civilizations through independence movements to the modern era.", Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", Location = "Liberal Arts 215", DepartmentId = 5, InstructorId = 5 },

            // Chemistry
            new() { Id = 14, Code = "CHEM 101", Title = "General Chemistry I", Description = "Fundamentals of chemistry including atomic structure, bonding, stoichiometry, and states of matter. Weekly lab included.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Location = "Chemistry Building 101", DepartmentId = 6, InstructorId = 6 },
            new() { Id = 15, Code = "CHEM 301", Title = "Organic Chemistry I", Description = "Structure, reactivity, and synthesis of organic compounds. Covers nomenclature, stereochemistry, and reaction mechanisms.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", Location = "Chemistry Building 205", DepartmentId = 6, InstructorId = 6, IsFeatured = true },

            // Psychology
            new() { Id = 16, Code = "PSY 101", Title = "Introduction to Psychology", Description = "Survey of major topics in psychology including perception, cognition, development, personality, and psychological disorders.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", Location = "Behavioral Science 100", DepartmentId = 7, InstructorId = 7, IsFeatured = true },
            new() { Id = 17, Code = "PSY 250", Title = "Cognitive Psychology", Description = "Study of mental processes including attention, memory, language, problem solving, and decision making.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", Location = "Behavioral Science 210", DepartmentId = 7, InstructorId = 7 },

            // Economics
            new() { Id = 18, Code = "ECON 101", Title = "Principles of Microeconomics", Description = "Introduction to microeconomic theory including supply and demand, market structures, consumer behavior, and welfare economics.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Location = "Business Hall 120", DepartmentId = 8, InstructorId = 8 },
            new() { Id = 19, Code = "ECON 102", Title = "Principles of Macroeconomics", Description = "Study of aggregate economic activity including GDP, inflation, unemployment, monetary and fiscal policy, and international trade.", Credits = 3, Schedule = "Tue/Thu 10:30–11:50 AM", Location = "Business Hall 120", DepartmentId = 8, InstructorId = 8, IsFeatured = true },
            new() { Id = 20, Code = "ECON 320", Title = "International Economics", Description = "Analysis of international trade theory, trade policy, exchange rates, and the global financial system.", Credits = 3, Schedule = "Mon/Wed 3:00–4:20 PM", Location = "Business Hall 215", DepartmentId = 8, InstructorId = 8 },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Instructor? GetInstructor(int id) => _instructors.FirstOrDefault(i => i.Id == id);
}

