@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Browse Courses</PageTitle>

<h1 class="mb-4">Browse Courses</h1>

<form method="get" action="/courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <label for="search" class="form-label">Search</label>
        <input type="text" class="form-control" id="search" name="search" value="@Search"
               placeholder="Search by title, code, or description…" />
    </div>
    <div class="col-md-4">
        <label for="departmentId" class="form-label">Department</label>
        <select class="form-select" id="departmentId" name="departmentId">
            <option value="">All Departments</option>
            @foreach (var dept in _departments)
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2 d-flex align-items-end gap-2">
        <button type="submit" class="btn btn-primary">Filter</button>
        <a href="/courses" class="btn btn-outline-secondary">Clear</a>
    </div>
</form>

@if (_courses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <p class="text-muted mb-3">Showing @_courses.Count course(s)</p>
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Schedule</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in _courses)
                {
                    var dept = Catalog.GetDepartment(course.DepartmentId);
                    <tr>
                        <td><strong>@course.Code</strong></td>
                        <td>@course.Title</td>
                        <td>@dept?.Name</td>
                        <td>@course.Credits</td>
                        <td class="text-nowrap">@course.Schedule</td>
                        <td>
                            <a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Course> _courses = new();
    private List<Department> _departments = new();

    protected override void OnInitialized()
    {
        _departments = Catalog.GetDepartments();
        _courses = Catalog.SearchCourses(Search, DepartmentId);
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

@if (_course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <div class="alert alert-warning">
        <h4>Course Not Found</h4>
        <p>The requested course could not be found.</p>
        <a href="/courses" class="btn btn-primary">Back to Courses</a>
    </div>
}
else
{
    <PageTitle>@_course.Code — @_course.Title</PageTitle>

    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/courses">Courses</a></li>
            @if (_department is not null)
            {
                <li class="breadcrumb-item"><a href="/courses?departmentId=@_department.Id">@_department.Name</a></li>
            }
            <li class="breadcrumb-item active" aria-current="page">@_course.Code</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-lg-8">
            <h1 class="mb-1">@_course.Code — @_course.Title</h1>
            <div class="mb-3">
                @if (_department is not null)
                {
                    <span class="badge bg-primary me-1">@_department.Name</span>
                }
                <span class="badge bg-secondary">@_course.Credits Credits</span>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h5 class="card-title">Description</h5>
                    <p class="card-text">@_course.Description</p>
                </div>
            </div>

            <div class="row g-3 mb-4">
                <div class="col-md-6">
                    <div class="card h-100">
                        <div class="card-body">
                            <h6 class="card-subtitle mb-2 text-muted">Schedule</h6>
                            <p class="card-text">@_course.Schedule</p>
                        </div>
                    </div>
                </div>
                <div class="col-md-6">
                    <div class="card h-100">
                        <div class="card-body">
                            <h6 class="card-subtitle mb-2 text-muted">Location</h6>
                            <p class="card-text">@_course.Location</p>
                        </div>
                    </div>
                </div>
            </div>

            <div class="mt-3">
                <a href="/enroll?courseId=@_course.Id" class="btn btn-primary me-2">Request Enrollment</a>
                <a href="/courses" class="btn btn-outline-secondary">Back to Courses</a>
            </div>
        </div>

        <div class="col-lg-4">
            @if (_instructor is not null)
            {
                <div class="card shadow-sm">
                    <div class="card-body">
                        <h5 class="card-title">Instructor</h5>
                        <h6 class="mb-1">@_instructor.Name</h6>
                        <p class="text-muted small mb-2">@_instructor.Title</p>
                        <p class="card-text small">@_instructor.Bio</p>
                        <a href="mailto:@_instructor.Email" class="text-decoration-none">@_instructor.Email</a>
                    </div>
                </div>
            }
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? _course;
    private Department? _department;
    private Instructor? _instructor;

    protected override void OnInitialized()
    {
        _course = Catalog.GetCourse(Id);
        if (_course is not null)
        {
            _department = Catalog.GetDepartment(_course.DepartmentId);
            _instructor = Catalog.GetInstructor(_course.InstructorId);
        }
    }
}

@page "/departments"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Departments</PageTitle>

<h1 class="mb-4">Departments</h1>

<div class="row row-cols-1 row-cols-md-2 g-4">
    @foreach (var dept in _departments)
    {
        var courseCount = Catalog.GetCoursesByDepartment(dept.Id).Count;
        <div class="col">
            <div class="card h-100 shadow-sm">
                <div class="card-body">
                    <h4 class="card-title">@dept.Name <span class="badge bg-secondary fs-6">@dept.Code</span></h4>
                    <p class="card-text">@dept.Description</p>
                    <p class="text-muted small">@courseCount course(s) available</p>
                </div>
                <div class="card-footer bg-transparent">
                    <a href="/courses?departmentId=@dept.Id" class="btn btn-outline-primary">View Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
