 @page "/enroll"
 @using UniversityCourseCatalog.Models
 @using UniversityCourseCatalog.Services
 @inject CatalogService Catalog

 <PageTitle>Enrollment Request</PageTitle>

 <h1 class="mb-4">Enrollment Request</h1>

 @if (_submitted)
 {
     <div class="alert alert-success">
         <h4 class="alert-heading">Request Submitted!</h4>
         <p>
             Thank you, <strong>@_model.StudentName</strong>. Your enrollment request for
             <strong>@(_selectedCourse?.Code) — @(_selectedCourse?.Title)</strong> has been received.
         </p>
         <p class="mb-0">You will receive a confirmation at <strong>@_model.Email</strong> once your request is processed.</p>
         <hr />
         <a href="/courses" class="btn btn-primary me-2">Browse More Courses</a>
         <a href="/enroll" class="btn btn-outline-secondary">Submit Another Request</a>
     </div>
 }
 else
 {
     <div class="row">
         <div class="col-lg-8">
             <div class="card shadow-sm">
                 <div class="card-body">
                     <form method="post" @formname="enrollment" @onsubmit="HandleSubmit">
                         <AntiforgeryToken />

                         <div class="mb-3">
                             <label for="studentName" class="form-label">Full Name <span class="text-danger">*</span></label>
                             <input type="text" class="form-control" id="studentName" name="_model.StudentName"
                                    value="@_model.StudentName" required maxlength="100" />
                         </div>

                         <div class="mb-3">
                             <label for="studentId" class="form-label">Student ID <span class="text-danger">*</span></label>
                             <input type="text" class="form-control" id="studentId" name="_model.StudentId"
                                    value="@_model.StudentId" required
                                    pattern="[A-Za-z0-9\-]+" title="Letters, numbers, and hyphens only" />
                         </div>

                         <div class="mb-3">
                             <label for="email" class="form-label">Email Address</label>
                             <input type="email" class="form-control" id="email" name="_model.Email"
                                    value="@_model.Email" />
                         </div>

                         <div class="mb-3">
                             <label for="courseId" class="form-label">Course <span class="text-danger">*</span></label>
                             <select class="form-select" id="courseId" name="_model.CourseId" required>
                                 <option value="">— Select a course —</option>
                                 @foreach (var course in _courses)
                                 {
                                     <option value="@course.Id" selected="@(_model.CourseId == course.Id)">
                                         @course.Code — @course.Title (@course.Credits cr)
                                     </option>
                                 }
                             </select>
                         </div>

                         <div class="mb-3">
                             <label for="notes" class="form-label">Additional Notes</label>
                             <textarea class="form-control" id="notes" name="_model.Notes" rows="3">@_model.Notes</textarea>
                         </div>

                         <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
                     </form>
                 </div>
             </div>
         </div>

         <div class="col-lg-4">
             <div class="card bg-light">
                 <div class="card-body">
                     <h6>How It Works</h6>
                     <ol class="small mb-0">
                         <li class="mb-2">Fill out the form with your details and select a course.</li>
                         <li class="mb-2">Submit your enrollment request.</li>
                         <li class="mb-2">The registrar's office will review and process your request.</li>
                         <li>You'll receive a confirmation email once approved.</li>
                     </ol>
                 </div>
             </div>
         </div>
     </div>
 }

 @code {
     [SupplyParameterFromQuery] public int? CourseId { get; set; }
     [SupplyParameterFromForm] private EnrollmentRequest? _model { get; set; }

     private List<Course> _courses = new();
     private Course? _selectedCourse;
     private bool _submitted;

     protected override void OnInitialized()
     {
         _courses = Catalog.GetCourses();
         _model ??= new EnrollmentRequest();

         if (CourseId.HasValue && _model.CourseId == 0)
         {
             _model.CourseId = CourseId.Value;
         }
     }

     private void HandleSubmit()
     {
         if (_model is null) return;
         _selectedCourse = Catalog.GetCourse(_model.CourseId);
         _submitted = true;
     }
 }

